import{_ as r,c as o,o as d,a3 as e}from"./chunks/framework.CTM16EAR.js";const m=JSON.parse('{"title":"Pomotention Timer · 14 天锚定单","description":"","frontmatter":{"search":false},"headers":[],"relativePath":"dev-log/timer-14d-anchor.md","filePath":"dev-log/timer-14d-anchor.md","lastUpdated":1781162755000}'),n={name:"dev-log/timer-14d-anchor.md"};function a(i,t,s,l,g,h){return d(),o("div",null,t[0]||(t[0]=[e('<h1 id="pomotention-timer-·-14-天锚定单" tabindex="-1">Pomotention Timer · 14 天锚定单 <a class="header-anchor" href="#pomotention-timer-·-14-天锚定单" aria-label="Permalink to &quot;Pomotention Timer · 14 天锚定单&quot;">​</a></h1><p>落地前问卷结论（2026-05-25）。执行 Timer 独立 Win 包冲刺时以此为准；与 <a href="./SOP/RELEASE-dev.html">RELEASE-dev</a> 主站发布流程并行、互不替代。</p><hr><h2 id="一句话" tabindex="-1">一句话 <a class="header-anchor" href="#一句话" aria-label="Permalink to &quot;一句话&quot;">​</a></h2><p>在 <strong>14 天内</strong>，为 <strong>「只要电脑专注计时」的用户</strong>（从现有 60 人 / 社群等自然来即可）交付 <strong>Windows Timer 安装包</strong>；验证 <strong>累计 ≥5 次完成工作段</strong>（A-松，可不点名）；为此 <strong>暂不做收费、不做手机 Timer 专用 PWA、不做登录同步</strong>；<strong>完整版 Pomotention 保持免费</strong>，Timer 通过中性脚注引流完整版。</p><hr><h2 id="_14-天后怎样算赢" tabindex="-1">14 天后怎样算赢 <a class="header-anchor" href="#_14-天后怎样算赢" aria-label="Permalink to &quot;14 天后怎样算赢&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项</th><th>约定</th></tr></thead><tbody><tr><td><strong>主指标（A-松）</strong></td><td>对外发出 <strong>Win Timer 安装包</strong>；本机统计 <strong>累计 ≥5 次「工作段完成」</strong></td></tr><tr><td><strong>不要求</strong></td><td>事先点名 5 人、逐一访谈</td></tr><tr><td><strong>建议</strong></td><td>自己先用顺；完成数中应有一部分来自「丢出去」之后，而非仅自测</td></tr><tr><td><strong>对外主交付</strong></td><td><strong>Windows 安装包（必达）</strong></td></tr><tr><td><strong>可选 bonus</strong></td><td>无签名 <strong>Mac .dmg</strong>（有人能装即可；不为 Mac 单独耗一周）</td></tr><tr><td><strong>这两周</strong></td><td><strong>不收款</strong>（Gumroad 等放下一轮）</td></tr></tbody></table><hr><h2 id="产品定义-独立完整小产品-非阉割版" tabindex="-1">产品定义（独立完整小产品，非阉割版） <a class="header-anchor" href="#产品定义-独立完整小产品-非阉割版" aria-label="Permalink to &quot;产品定义（独立完整小产品，非阉割版）&quot;">​</a></h2><ul><li><strong>包含</strong>：单次番茄 + 休息、Pizza 番茄列车、白噪音、置顶/迷你窗、顶上可编辑状态文案（<code>pomodoroStateMessage</code>）、Timer 相关设置（时长、声音、紧凑等）。</li><li><strong>不包含</strong>：planner / 任务 / 登录 / 云同步 / 与完整版 planner 数据互导；顶栏跑马灯「今日目标」。</li><li><strong>统计（档 1）</strong>：本机 <strong>今日完成工作段数</strong> 展示；<strong>不做</strong> 导出、点击流、会话列表（档 2 以后再说）。</li><li><strong>置顶窗</strong>：<strong>不进设置</strong>；先退出置顶再改；<strong>单个番茄模式也要能开关白噪音</strong>（置顶时仍可操作）。</li><li><strong>UI 壳</strong>：保留现网 <strong>顶栏 = 置顶 Pin + 设置</strong>；去掉其它视图切换、数据库、登录等；设置页只保留 Timer 相关项。</li></ul><p><strong>对外一句话（桌面包）</strong></p><blockquote><p>电脑工作时窗口置顶一直看见；番茄列车帮你连续跑一整组专注；自带白噪音，番茄长短也能自己设。</p></blockquote><p><strong>与完整版 Pomotention</strong></p><table tabindex="0"><thead><tr><th>项</th><th>约定</th></tr></thead><tbody><tr><td>关系</td><td>Timer 可引流完整版（<strong>c</strong>）；完整版 <strong>继续免费</strong>（完整版若未来收费 → 倾向 <strong>订阅</strong>；Timer 若未来收费 → 倾向 <strong>一次性买断</strong>，非订阅）</td></tr><tr><td>页脚</td><td><strong>中性脚注（a）</strong>：「需要日程与任务？打开完整版 Pomotention →」</td></tr><tr><td>以后</td><td>Timer 数据迁完整版的「大升级」单独立项，<strong>不进本 14 天</strong></td></tr></tbody></table><hr><h2 id="用户、发布与支持" tabindex="-1">用户、发布与支持 <a class="header-anchor" href="#用户、发布与支持" aria-label="Permalink to &quot;用户、发布与支持&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项</th><th>约定</th></tr></thead><tbody><tr><td>用户池</td><td>已注册 ~60 人、番茄学习群、同事、小红书等；<strong>丢出去</strong>即可，不凑 5 个实名制</td></tr><tr><td>支持</td><td>一页安装/置顶/白噪音说明；<strong>一个</strong>主反馈渠道；文字回复；<strong>每天约 30 分钟</strong> 上限</td></tr><tr><td>热情过载</td><td>可用模板：「感谢！这轮我在收集中，会先修共性问题；你的情况我记下了，X 天内回复。」</td></tr><tr><td>最怕白费</td><td>两周时间在主项目 <strong>新功能 / 异想天开</strong>，没朝 Timer Win 包推进</td></tr></tbody></table><hr><h2 id="时间与主项目" tabindex="-1">时间与主项目 <a class="header-anchor" href="#时间与主项目" aria-label="Permalink to &quot;时间与主项目&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项</th><th>约定</th></tr></thead><tbody><tr><td>投入</td><td>平均每天 <strong>≥3 小时</strong></td></tr><tr><td>主项目</td><td><strong>基本停更（c）</strong>；<strong>不修新功能</strong>；<strong>会修</strong> 现网 blocker（如换天 bug）</td></tr><tr><td>第 7 天检查点</td><td>若尚不能给别人装 → <strong>砍 scope（a）</strong>，先「能装 + 能跑完一轮工作段」</td></tr></tbody></table><p><strong>每天自检</strong></p><blockquote><p>今天有没有让「多一个人能装上并完成一轮工作段」更近？</p></blockquote><hr><h2 id="技术路线" tabindex="-1">技术路线 <a class="header-anchor" href="#技术路线" aria-label="Permalink to &quot;技术路线&quot;">​</a></h2><ul><li><strong>同 repo</strong>，不新 repo：Timer 瘦入口 + 第二套 Tauri 构建（独立 <code>identifier</code> / 产品名等）；<strong>不必</strong>为打包单独维护长期分支。</li><li><strong>Win 必达</strong>；Mac 无签名 dmg 可作 bonus；<strong>不做</strong> Timer 专用手机 PWA 子域、应用商店、Mac 签名/公证。</li></ul><hr><h2 id="建议-14-天节奏" tabindex="-1">建议 14 天节奏 <a class="header-anchor" href="#建议-14-天节奏" aria-label="Permalink to &quot;建议 14 天节奏&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>天数</th><th>焦点</th></tr></thead><tbody><tr><td>1</td><td>1～3</td><td>Timer 瘦壳：仅钟 + 瘦顶栏；<code>tauri build</code> 出 Win 包；自己跑通 1 轮</td></tr><tr><td>2</td><td>4～6</td><td>置顶可靠；单次模式白噪音；Timer 设置瘦身；档 1 今日计数</td></tr><tr><td>3</td><td>7</td><td><strong>检查点</strong>：能否给别人装？否 → 按 <a href="#第-7-天砍-scope-顺序">砍 scope 顺序</a></td></tr><tr><td>4</td><td>8～10</td><td>一页说明；丢到主渠道；累计 ≥5 工作段</td></tr><tr><td>5</td><td>11～14</td><td>修 blocker；脚注链完整版；可选收集 3 条非己反馈原话</td></tr></tbody></table><hr><h2 id="第-7-天砍-scope-顺序" tabindex="-1">第 7 天砍 scope 顺序 <a class="header-anchor" href="#第-7-天砍-scope-顺序" aria-label="Permalink to &quot;第 7 天砍 scope 顺序&quot;">​</a></h2><p>从下到上砍；砍前一层仍算检查点未通过。</p><ol><li>档 1「今日 🍅 计数」UI</li><li>单次番茄模式白噪音按钮（若列车模式仍可用白噪音则暂可砍此项）</li><li>Pizza 序列（保留单次番茄 + 休息）</li><li>设置页精简（暂用默认时长/声音，仅保留置顶与核心按钮）</li><li>Mac dmg（只发 Win）</li></ol><p><strong>不可砍</strong>：Win 能安装、能完成 <strong>至少 1 次工作段</strong>（Wind up → 正常结束或 Squash）、置顶可用。</p><hr><h2 id="两周绝对不做" tabindex="-1">两周绝对不做 <a class="header-anchor" href="#两周绝对不做" aria-label="Permalink to &quot;两周绝对不做&quot;">​</a></h2><ol><li>新 repo</li><li>iPhone / Android <strong>Timer 专用</strong> PWA 子域（提前做完再说不算本盒）</li><li>应用商店上架</li><li>收费 / Gumroad / 标价落地</li><li>登录、云同步、与完整版 planner 数据互导</li><li>会话导出、点击流日志（统计档 2）</li><li>主项目 <strong>新功能</strong></li><li>Mac 签名 / 公证（无签名 dmg 仅作 bonus）</li><li>系统级专注锁（引导式访问等仅可写文档提示）</li></ol><hr><h2 id="价值观与商业化-长期红线" tabindex="-1">价值观与商业化（长期红线） <a class="header-anchor" href="#价值观与商业化-长期红线" aria-label="Permalink to &quot;价值观与商业化（长期红线）&quot;">​</a></h2><p><strong>不做</strong>：广告；卖数据/行为追踪换钱；复杂 DRM；Timer 订阅制；阉割 Timer 逼用户上完整版（灰掉 tab 类）。</p><p><strong>在乎</strong>：可持续收入 + 发布/反馈闭环；低客服是底线（非炫耀目标）。</p><p><strong>独立开发者日课（本 14 天）</strong></p><blockquote><p>我今天只承诺：30 分钟回 Timer 安装/闪退；功能想法记 backlog；14 天不收钱。</p></blockquote><hr><h2 id="第-15-天以后-刻意不计入赢" tabindex="-1">第 15 天以后（刻意不计入赢） <a class="header-anchor" href="#第-15-天以后-刻意不计入赢" aria-label="Permalink to &quot;第 15 天以后（刻意不计入赢）&quot;">​</a></h2><ul><li>Gumroad（或类似）+ Timer <strong>一次性买断</strong> + 自动发 Win 包；熟悉流程即可，不强求首单。</li><li>Timer → 完整版数据迁移。</li><li>手机 Timer PWA / 替代实体钟。</li><li>完整版订阅（若做）。</li></ul><hr><h2 id="用-pomotention-管本-sprint-与软件内-backlog" tabindex="-1">用 Pomotention 管本 sprint（与软件内 backlog） <a class="header-anchor" href="#用-pomotention-管本-sprint-与软件内-backlog" aria-label="Permalink to &quot;用 Pomotention 管本 sprint（与软件内 backlog）&quot;">​</a></h2><ul><li>长期 <code>#list</code> 活动 + Task 内 <code>- [ ]</code> 可继续用；冲刺另开 <strong><code>Timer 14d</code></strong> 无日期活动，避免与百年待办混页。</li><li>Task 清单用 <code>[now]</code> / <code>[later]</code>；计划表 <strong>今天</strong> 只放 <code>[now]</code> 里 1～3 条。</li><li>清单过长：优先 Task 内「收件箱 / 已完成」分区；主题或阶段变了再 <strong>新开活动</strong>，旧条 archive。</li><li>操作说明见 <a href="./../guide/practices/long-horizon-inventory.html">长期事项与待办库存</a>。</li></ul><hr><h2 id="问卷索引-便于回溯" tabindex="-1">问卷索引（便于回溯） <a class="header-anchor" href="#问卷索引-便于回溯" aria-label="Permalink to &quot;问卷索引（便于回溯）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>题</th><th>结论</th></tr></thead><tbody><tr><td>赢</td><td>A-松</td></tr><tr><td>交付</td><td>Win 安装包</td></tr><tr><td>白费</td><td>scope 被主项目吸走</td></tr><tr><td>用户</td><td>现有池子丢出去</td></tr><tr><td>差异</td><td>置顶 + 列车 + 白噪音 + 可调时长</td></tr><tr><td>与完整版</td><td>c 引流；完整版免费</td></tr><tr><td>平台</td><td>Win 必达；3/4/5 不做</td></tr><tr><td>功能</td><td>Timer 全要；无 5/6；统计档 1</td></tr><tr><td>设置</td><td>顶栏；置顶不设；单次白噪音要</td></tr><tr><td>脚注</td><td>a 中性</td></tr><tr><td>收费</td><td>两周不做</td></tr><tr><td>商业红线</td><td>236 不要；Timer 非订阅</td></tr><tr><td>目标</td><td>1+3</td></tr><tr><td>支持</td><td>a，30min/日</td></tr><tr><td>时间</td><td>3h+/日</td></tr><tr><td>主项目</td><td>c + blocker 可修</td></tr><tr><td>第 7 天</td><td>砍 scope a</td></tr></tbody></table>',52)]))}const b=r(n,[["render",a]]);export{m as __pageData,b as default};
